use std::collections::HashMap;

fn longest_arith_seq_length(nums: Vec<i32>) -> i32 {
    let n = nums.len();
    let mut dp = vec![HashMap::new(); n];
    let mut res = 0;
    for i in 1..n {
        for j in 0..i {
            let diff = nums[i]-nums[j];
            let max = dp[j].get(&diff).unwrap_or(&1)+1;
            dp[i].insert(diff, max);
            res = res.max(max);
        }
    }

    res
}

fn generate_random_nums() -> Vec<i32> {
    (0..1000).map(|_| rand::random_range(0..=500)).collect()
}

